import { describe, test, expect } from 'vitest';
import { outputNotify, wrapAt } from '../../lib/output.js';

describe('wrapAt', () => {
  test('returns text unchanged when already under width', () => {
    expect(wrapAt('short line', 80)).toBe('short line');
  });

  test('preserves explicit newlines', () => {
    expect(wrapAt('line one\nline two', 80)).toBe('line one\nline two');
  });

  test('wraps a long line at word boundaries', () => {
    const text = 'the quick brown fox jumps over the lazy dog repeatedly each morning';
    const wrapped = wrapAt(text, 30);
    const lines = wrapped.split('\n');
    expect(lines.every(l => l.length <= 30)).toBe(true);
    expect(lines.join(' ').replace(/\s+/g, ' ').trim()).toBe(text);
  });

  test('hard-splits a word longer than maxWidth', () => {
    const text = 'normal word andthenaverylongunbreakableidentifier end';
    const wrapped = wrapAt(text, 15);
    const lines = wrapped.split('\n');
    expect(lines.every(l => l.length <= 15)).toBe(true);
  });

  test('returns empty string as-is', () => {
    expect(wrapAt('', 80)).toBe('');
  });
});

describe('outputNotify', () => {
  test('drops empty messages silently', () => {
    const r = outputNotify('', { prefix: 'x' });
    expect(r.hookSpecificOutput).toBeUndefined();
    expect(r.continue).toBe(true);
    expect(r.suppressOutput).toBe(true);
  });

  test('drops whitespace-only messages silently', () => {
    const r = outputNotify('   \n\n  ', { prefix: 'x' });
    expect(r.hookSpecificOutput).toBeUndefined();
  });

  test('applies prefix and defaults to PostToolUse event', () => {
    const r = outputNotify('hi', { prefix: 'foo' });
    const ctx = (r.hookSpecificOutput as { additionalContext?: string })?.additionalContext;
    expect(ctx).toBe('[foo] hi');
    expect((r.hookSpecificOutput as { hookEventName?: string })?.hookEventName).toBe('PostToolUse');
  });

  test('respects custom event name', () => {
    const r = outputNotify('hi', { prefix: 'foo', event: 'UserPromptSubmit' });
    expect((r.hookSpecificOutput as { hookEventName?: string })?.hookEventName).toBe('UserPromptSubmit');
  });

  test('wraps long messages at 80 by default', () => {
    const long = 'a '.repeat(60).trim(); // 119 chars
    const r = outputNotify(long, { prefix: 'wrap' });
    const ctx = (r.hookSpecificOutput as { additionalContext: string }).additionalContext;
    const lines = ctx.split('\n');
    expect(lines.every(l => l.length <= 80)).toBe(true);
  });

  test('respects custom maxWidth', () => {
    const text = 'the quick brown fox jumps over the lazy dog';
    const r = outputNotify(text, { prefix: 'p', maxWidth: 20 });
    const ctx = (r.hookSpecificOutput as { additionalContext: string }).additionalContext;
    expect(ctx.split('\n').every(l => l.length <= 20)).toBe(true);
  });

  test('indents continuation lines to align with prefix', () => {
    const text = 'a '.repeat(60).trim();
    const r = outputNotify(text, { prefix: 'align' });
    const ctx = (r.hookSpecificOutput as { additionalContext: string }).additionalContext;
    const lines = ctx.split('\n');
    expect(lines[0]).toMatch(/^\[align\] /);
    if (lines.length > 1) {
      // continuation lines are indented by the prefix width ([align]<space> = 8)
      expect(lines[1]).toMatch(/^ {8}/);
    }
  });
});
